import axios from 'axios';

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000/api/admin';

const api = axios.create({
  baseURL: BASE_URL,
  headers: { 'Content-Type': 'application/json' },
});

// Attach JWT to every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Auto-refresh on 401
api.interceptors.response.use(
  (res) => res,
  async (error) => {
    const original = error.config;
    if (error.response?.status === 401 && !original._retry) {
      original._retry = true;
      try {
        const refresh = localStorage.getItem('refresh_token');
        const { data } = await axios.post(`${BASE_URL}/auth/token/refresh/`, { refresh });
        localStorage.setItem('access_token', data.access);
        original.headers.Authorization = `Bearer ${data.access}`;
        return api(original);
      } catch {
        localStorage.clear();
        window.location.href = '/login';
      }
    }
    return Promise.reject(error);
  }
);

// ── Auth ──────────────────────────────────────────────────────────────────────

export const authAPI = {
  register: (data) => api.post('/auth/register/', data),
  sendOtp: (phone_number) => api.post('/auth/send-otp/', { phone_number }),
  verifyOtp: (phone_number, code) => api.post('/auth/verify/', { phone_number, code }),
  login: (phone_number, password) => api.post('/auth/login/', { phone_number, password }),
  forgotPassword: (phone_number) => api.post('/auth/forgot-password/', { phone_number }),
  resetPassword: (phone_number, code, new_password) =>
    api.post('/auth/reset-password/', { phone_number, code, new_password }),
  createAdmin: (data) => api.post('/auth/create-admin/', data),
};

export default api;
